public int makeChocolate(int small, int big, int goal) {
    if (big * 5 >= goal) {
        int bigUsed = goal / 5;
        if (bigUsed > big) {
            bigUsed = big;
        }
        int remaining = goal - bigUsed * 5;
        if (small < remaining) {
            return -1;
        }
        return small - remaining;
    } else {
        int remaining = goal - big * 5;
        if (small < remaining) {
            return -1;
        }
        return small - remaining;
    }
}

